/**
 * @file Type definitions for Mittwald SSH/SFTP and Backup APIs
 * @module types/mittwald/ssh-backup
 */

// SSH Key Types
export interface SshKey {
  id: string;
  label: string;
  publicKey: string;
  fingerprint: string;
  createdAt: string;
  expiresAt?: string;
}

export interface CreateSshKeyRequest {
  label: string;
  publicKey: string;
  expiresAt?: string;
}

export interface UpdateSshKeyRequest {
  label?: string;
  expiresAt?: string;
}

// SSH User Types
export interface SshUser {
  id: string;
  username: string;
  description?: string;
  homeDirectory: string;
  publicKeys: string[];
  status: 'active' | 'inactive';
  createdAt: string;
  updatedAt?: string;
}

export interface CreateSshUserRequest {
  username: string;
  description?: string;
  publicKeys?: string[];
}

export interface UpdateSshUserRequest {
  description?: string;
  publicKeys?: string[];
  status?: 'active' | 'inactive';
}

// SFTP User Types
export interface SftpUser {
  id: string;
  username: string;
  description?: string;
  homeDirectory: string;
  password?: string;
  status: 'active' | 'inactive';
  createdAt: string;
  updatedAt?: string;
}

export interface CreateSftpUserRequest {
  username: string;
  description?: string;
  password?: string;
}

export interface UpdateSftpUserRequest {
  description?: string;
  password?: string;
  status?: 'active' | 'inactive';
}

// Backup Types
export interface ProjectBackup {
  id: string;
  projectId: string;
  description?: string;
  status: 'Pending' | 'Creating' | 'Completed' | 'Failed' | 'Cancelled';
  deletable: boolean;
  requestedAt: string;
  createdAt?: string;
  expiresAt?: string;
  parentId?: string;
  export?: ProjectBackupExport;
}

export interface ProjectBackupExport {
  format: string;
  withPassword: boolean;
  phase?: 'Pending' | 'Exporting' | 'Failed' | 'Completed' | 'Expired';
  downloadURL?: string;
  expiresAt?: string;
